INSERT INTO engine_bug_queue (bug_class, title, severity, owner_cluster, root_cause, prevention_rule, probe_type, probe_logic, status, concepts_affected, fixed_in_files, discovered_in_session, row_type) VALUES
('torque_scenario_no_contextual_controls', 'torque_on_loop_uniform_field scenario cannot do Rule-31c per-state contextual controls — the slider panel is all-or-nothing (no row-wrapper ids, no applyVisibleControls call), shown only at the explore state; guided states expose no state-relevant slider', 'MAJOR', 'peter_parker:renderer_primitives', 'Surfaced by retrofit_surgeon 2026-07-05 (Socratic->Rule-31 narration retrofit, JSON-only). The scenario''s #torque_sliders panel is one div of four bare label+input pairs (N/I/B/theta) with NO row-wrapper ids, and the per-frame gate is stateDef.show_sliders && isTorque (src/lib/renderers/field_3d_renderer.ts ~L27748) with NO applyVisibleControls({...}, stateDef.visible_controls) call — unlike force_on_current_wire (~L27657), magnetic_field_circular_loop (~L11391), faraday (~L27044) which DO wrap rows + call applyVisibleControls. So Rule-31c (each guided state exposes ONLY its relevant slider(s)) is not implementable today; only STATE_11 (explore) shows the panel — the OLD last-state-only pattern. Retrofit_surgeon correctly did NOT fake it with an inert JSON visible_controls field. TWO-PART FIX for the rebuild pass: (a) renderer_primitives adds row-wrapper ids (tor_n_row/tor_i_row/tor_b_row/tor_theta_row) inside #torque_sliders + an applyVisibleControls call in the torqueSlidersEl branch, mirroring force_on_current_wire; (b) json_author adds per-state visible_controls declarations to the guided states (e.g. STATE_5 = N,I).', 'A field_3d scenario used by a Rule-31 concept must support per-state contextual controls (row-wrapper ids + applyVisibleControls reading stateDef.visible_controls) BEFORE the concept is authored/retrofitted to Rule 31 — a Socratic->straightforward narration retrofit alone does not make a concept Rule-31-compliant if its scenario is control-incapable.', 'manual', 'For torque_on_current_loop_in_field, confirm each guided state exposes only its relevant slider row(s) and the explore state exposes all. If the panel is all-or-nothing (only the explore state shows any slider), Rule-31c is unmet.', 'OPEN', ARRAY['torque_on_current_loop_in_field'], ARRAY[]::text[], 'session_2026-07-05_torque_socratic_retrofit_rule31_gaps', 'incident'),
('torque_static_early_states', 'torque_on_current_loop_in_field STATE_1/2/3 are rotation_mode "static" (zero motion) — violates Rule 31b "no static state; every state alive with distinct motion"', 'MODERATE', 'ambiguous', 'Surfaced 2026-07-05 during the Socratic->Rule-31 retrofit (out of scope for that JSON-only narration delta; noted, not fixed). STATE_1 (geometry setup), STATE_2 (F on left side), STATE_3 (F on right side, sum F=0) are authored rotation_mode: "static" — they present a still picture while the narration plays, which Rule 31b forbids (every state must earn its place with distinct motion — a watch-this beat still needs auto-playing choreography, motion and interactivity being separate axes). This is a DESIGN decision (what motion each early beat should show — e.g. the force vectors animating in, or a gentle idle rotation), so it is owner-ambiguous pending founder/architect direction, then renderer_primitives to implement. Part of the deferred torque Rule-31 rebuild pass, alongside torque_scenario_no_contextual_controls.', 'Every guided state (including setup / watch-this beats) must show distinct auto-playing motion (Rule 31b) — a rotation_mode "static" state is a design smell to resolve at author time, not ship.', 'manual', 'For each guided state, THE EYE motion profile (D-checks) must show sustained above-floor adjacent-frame motion; a state that is flat for its whole duration is a static-state violation.', 'OPEN', ARRAY['torque_on_current_loop_in_field'], ARRAY[]::text[], 'session_2026-07-05_torque_socratic_retrofit_rule31_gaps', 'incident')
